# Quarterly review of a sensitive security group, manager as reviewer
# Requires AccessReview.ReadWrite.All
$body = @{
    displayName            = 'Quarterly prod-access group review'
    startDateTime          = '2025-01-01T09:00:00Z'
    instanceDurationInDays = 14
    recurrence = @{
        pattern = @{ type = 'absoluteMonthly'; interval = 3; dayOfMonth = 1 }
        range   = @{ type = 'noEnd'; startDate = '2025-01-01' }
    }
    reviewers = @(
        @{ query = '/v1.0/users/<security-reviewer-oid>'; queryType = 'MicrosoftGraph' }
    )
    fallbackReviewers = @(
        @{ query = '/v1.0/users/<fallback-reviewer-oid>'; queryType = 'MicrosoftGraph' }
    )
    settings = @{
        mailNotificationsEnabled        = $true
        reminderNotificationsEnabled    = $true
        justificationRequiredOnApproval = $true
        defaultDecisionEnabled          = $true
        defaultDecision                 = 'Deny'
        instanceDurationInDays          = 14
        autoApplyDecisionsEnabled       = $true
        recommendationsEnabled           = $true
        recommendationLookBackDuration  = 'P30D'
    }
    scope = @{
        '@odata.type' = '#microsoft.graph.accessReviewQueryScope'
        query         = '/v1.0/groups/<group-id>/members/microsoft.graph.user'
        queryType     = 'MicrosoftGraph'
    }
} | ConvertTo-Json -Depth 8

$review = Invoke-MgGraphRequest -Method POST \
  -Uri 'https://graph.microsoft.com/v1.0/identityGovernance/accessReviews/definitions' \
  -Body $body -ContentType 'application/json'
Write-Host "Created review: $($review.id)"

# Monthly review of all users assigned to a specific enterprise application
$appReview = @{
    displayName            = 'Monthly Salesforce Admin review'
    startDateTime          = '2025-01-01T09:00:00Z'
    instanceDurationInDays = 21
    recurrence = @{
        pattern = @{ type = 'absoluteMonthly'; interval = 1; dayOfMonth = 1 }
        range   = @{ type = 'noEnd'; startDate = '2025-01-01' }
    }
    reviewers = @(
        @{ query = '/v1.0/servicePrincipals/<sp-oid>/owners'; queryType = 'MicrosoftGraph' }
    )
    settings = @{
        defaultDecision           = 'Recommendation'
        autoApplyDecisionsEnabled = $true
        recommendationsEnabled    = $true
    }
    scope = @{
        '@odata.type'    = '#microsoft.graph.principalResourceMembershipsScope'
        principalScopes = @(
            @{ '@odata.type' = '#microsoft.graph.accessReviewQueryScope'
               query = '/v1.0/users'; queryType = 'MicrosoftGraph' }
        )
        resourceScopes = @(
            @{ '@odata.type' = '#microsoft.graph.accessReviewQueryScope'
               query = '/v1.0/servicePrincipals/<salesforce-sp-oid>/appRoleAssignedTo'
               queryType = 'MicrosoftGraph' }
        )
    }
} | ConvertTo-Json -Depth 10

Invoke-MgGraphRequest -Method POST \
  -Uri 'https://graph.microsoft.com/v1.0/identityGovernance/accessReviews/definitions' \
  -Body $appReview -ContentType 'application/json'

# Multi-stage review: stage 1 = manager, stage 2 = compliance team
# Note: multi-stage uses the "stages" property on the definition
$body = @{
    displayName            = 'Two-stage quarterly review'
    startDateTime          = '2025-01-01T09:00:00Z'
    instanceDurationInDays = 28
    recurrence = @{
        pattern = @{ type = 'absoluteMonthly'; interval = 3; dayOfMonth = 1 }
        range   = @{ type = 'noEnd'; startDate = '2025-01-01' }
    }
    stages = @(
        @{
            durationInDays = 14
            stageId        = '1'
            dependsOn      = @()
            reviewers = @(
                @{ query = '/v1.0/users/<manager-reviewer-oid>'; queryType = 'MicrosoftGraph' }
            )
            fallbackReviewers = @(
                @{ query = '/v1.0/groups/<security-team-oid>/members'; queryType = 'MicrosoftGraph' }
            )
        },
        @{
            durationInDays = 14
            stageId        = '2'
            dependsOn      = @('1')
            reviewers = @(
                @{ query = '/v1.0/groups/<compliance-team-oid>/members'; queryType = 'MicrosoftGraph' }
            )
        }
    )
    settings = @{
        defaultDecision           = 'Deny'
        autoApplyDecisionsEnabled = $true
        recommendationsEnabled    = $true
        decisionHistoriesForReviewersEnabled = $true
    }
    scope = @{
        '@odata.type' = '#microsoft.graph.accessReviewQueryScope'
        query         = '/v1.0/groups/<sensitive-group-id>/members/microsoft.graph.user'
        queryType     = 'MicrosoftGraph'
    }
} | ConvertTo-Json -Depth 12

Invoke-MgGraphRequest -Method POST \
  -Uri 'https://graph.microsoft.com/v1.0/identityGovernance/accessReviews/definitions' \
  -Body $body -ContentType 'application/json'

# Review only members who have not signed in for 90+ days
# Use the inactiveDuration filter in the scope query
$inactiveReview = @{
    displayName            = 'Inactive member review (90+ days no sign-in)'
    startDateTime          = '2025-01-01T09:00:00Z'
    instanceDurationInDays = 14
    recurrence = @{
        pattern = @{ type = 'absoluteMonthly'; interval = 1; dayOfMonth = 1 }
        range   = @{ type = 'noEnd'; startDate = '2025-01-01' }
    }
    reviewers = @(
        @{ query = '/v1.0/users/<security-reviewer-oid>'; queryType = 'MicrosoftGraph' }
    )
    settings = @{
        defaultDecision           = 'Deny'
        autoApplyDecisionsEnabled = $true
        recommendationsEnabled    = $true
        recommendationLookBackDuration = 'P90D'
        inactiveDuration = 'P90D'
    }
    scope = @{
        '@odata.type' = '#microsoft.graph.accessReviewInactiveUsersQueryScope'
        query         = '/v1.0/groups/<group-id>/members/microsoft.graph.user'
        queryType     = 'MicrosoftGraph'
        inactiveDuration = 'P90D'
    }
} | ConvertTo-Json -Depth 8

Invoke-MgGraphRequest -Method POST \
  -Uri 'https://graph.microsoft.com/v1.0/identityGovernance/accessReviews/definitions' \
  -Body $inactiveReview -ContentType 'application/json'

# Review all B2B guest users assigned to a specific group
# Scope targets only userType = 'Guest' members
$guestReview = @{
    displayName            = 'Quarterly external guest review - prod-collab group'
    startDateTime          = '2025-01-01T09:00:00Z'
    instanceDurationInDays = 21
    recurrence = @{
        pattern = @{ type = 'absoluteMonthly'; interval = 3; dayOfMonth = 1 }
        range   = @{ type = 'noEnd'; startDate = '2025-01-01' }
    }
    reviewers = @(
        @{ query = '/v1.0/groups/<group-id>/owners'; queryType = 'MicrosoftGraph' }
    )
    settings = @{
        defaultDecision           = 'Deny'
        autoApplyDecisionsEnabled = $true
        recommendationsEnabled    = $true
    }
    scope = @{
        '@odata.type' = '#microsoft.graph.accessReviewQueryScope'
        query         = "/v1.0/groups/<group-id>/members/microsoft.graph.user?`$filter=userType eq 'Guest'"
        queryType     = 'MicrosoftGraph'
    }
} | ConvertTo-Json -Depth 8

Invoke-MgGraphRequest -Method POST \
  -Uri 'https://graph.microsoft.com/v1.0/identityGovernance/accessReviews/definitions' \
  -Body $guestReview -ContentType 'application/json'
